Rule.Source:
   
	import java.util.Iterator;
	import sailpoint.api.Certificationer;
	import sailpoint.api.ObjectUtil;
	import sailpoint.object.Certification;
	import sailpoint.object.CertificationEntity;
	import sailpoint.object.CertificationItem;  
	import sailpoint.object.Configuration;
	import sailpoint.object.Identity; 
	import sailpoint.object.Filter;
	import sailpoint.object.QueryOptions;
	import sailpoint.tools.Util;
	import org.apache.log4j.Logger;
  
  log.trace("CurrentEntity1: " + entity.toXml());
  
	Logger logger = Logger.getLogger("rule.Ascension.fodLocation.PreDelegationPeopleSoftAttestation");

	//Create Empty HashMap to Fulfill Expected Return of Pre-Delegation Rule
	Map results = new HashMap(); 
	logger.debug("##################### Rule-PreDelegation-PeopleoftAttestation starts ##################### ");
	//Get Certifier Info
	List certifierList = certification.getCertifiers();
	String certifierStr = certifierList.get(0);
	Identity certifier = context.getObjectByName(Identity.class, certifierStr);
	logger.debug("certifierStr: " + certifierStr);
	logger.debug("certifier: " + certifier);

	//Define Arguments for bulkReassign Method
	Identity handler = context.getObjectByName(Identity.class, "IDM Team");
	Identity recipient = new Identity(); //Conditionally set
	Identity fallBackRecipient = context.getObjectByName(Identity.class, "IDM Team");
	String refCertName = certification.getName();
	//String newCertName = refCertName + " (Self-Certification Avoidance)";
	//String description = "Automatically Reassigned as Per Policy (Self-Certification Avoidance)";
	String comments = ""; //Conditionally set
	Configuration sysConfig = context.getObjectByName(Configuration.class, "SystemConfiguration");
	logger.debug("fallBackRecipient: " + fallBackRecipient);
	logger.debug("handler: " + handler);
	
	//Intitialize Variables for Iterators
	//CertificationItem currentItem = null;

	List items = new ArrayList();
	List props = new ArrayList();
	List outList = null;
	List currentOut = new ArrayList();

	Identity currentMember = null;
	Identity currentOutIdentity = null;

	String currentMemberName = "";
	String currentTarget = entity.getTargetName();;
	List newCertifiers = new ArrayList();
  

	if (certifier.isWorkgroup() ) 
	{
		logger.debug("##################### Rule-PreDelegation-PeopleoftAttestation ends ##################### ");
		return results;
	}
	
	if (certifier == null || Util.nullSafeEq(currentTarget, certifierStr) || certifier.isInactive()) 
	{
		if( certifier != null && certifier.getManager() != null && !(certifier.getManager().isInactive()))
		{
		  certifier.load(); //Load to prevent LazyInitializationException
		  recipient = certifier.getManager();
		  recipient.load(); //Load to prevent LazyInitializationException
		  comments = "Automatically reassigned to Manager of " + certifier.getDisplayName();
      log.error("certifier.getDisplayName(): " + certifier.getDisplayName());
		} 
		else 
		{
		  recipient = fallBackRecipient;
      recipient.load(); //Load to prevent LazyInitializationException
		  comments = "Target Identity Cube - does not have a Manager; Automatically reassigned to fallback: " + fallBackRecipient.getName();
      log.error("recipient: " + recipient);
		}
		newCertifiers.add(recipient);
		logger.debug("recipient: " + recipient);
		logger.debug("comments: " + comments);
    log.trace("CurrentEntity2: " + entity.toXml());
		certification.add(entity);
		certification.setCertifierIdentities(newCertifiers);
		certification.setComments(comments);
		//logger.debug("new certification: " + certification.toXml());
		certification.setSelfCertificationReassignment(true); //Used to trigger condition in BulkReassignment EmailTemplate 
		context.saveObject(certification);
		new Certificationer(context).refresh(certification);
	}
	
	logger.debug("##################### Rule-PreDelegation-PeopleoftAttestation ends ##################### ");
	return results;
